record.field:
{
    "type": "object",
    "properties": {
        "member_name": {"type": "string", "description": "Name of the member to look up"},
        "member_id": {"type": "integer", "description": "ID of the member to look up"}
    }
}

{
    "type": "object",
    "properties": {
        "name": {"type": "string", "description": "Full name of the new member"},
        "email": {"type": "string", "format": "email", "description": "Email address"},
        "phone": {"type": "string", "description": "Phone number"}
    },
    "required": ["name"]
}

{
    "type": "object",
    "properties": {
        "member_name": {"type": "string", "description": "Name of the member to update"},
        "member_id": {"type": "integer", "description": "ID of the member"},
        "name": {"type": "string", "description": "New name"},
        "email": {"type": "string", "format": "email", "description": "New email"},
        "phone": {"type": "string", "description": "New phone"}
    },
    "required": ["member_name"]
}

{
    "type": "object",
    "properties": {
        "name": {"type": "string", "description": "Name of the new program"},
        "description": {"type": "string", "description": "Program description (optional)"},
        "active": {"type": "boolean", "description": "Whether the program is active", "default": true}
    },
    "required": ["name"]
}

{
    "type": "object",
    "properties": {
        "instructor_name": {"type": "string", "description": "Name of the instructor"},
        "name": {"type": "string", "description": "New display name"},
        "bio": {"type": "string", "description": "Short biography"},
        "active": {"type": "boolean", "description": "Whether the profile is active"}
    },
    "required": ["instructor_name"]
}

{
    "type": "object",
    "properties": {
        "member_name": {"type": "string", "description": "Name of the member"},
        "name": {"type": "string", "description": "Name of the emergency contact"},
        "phone": {"type": "string", "description": "Phone number"},
        "relationship": {"type": "string", "description": "Relationship (parent, sibling, etc.)"},
        "email": {"type": "string", "format": "email", "description": "Email address (optional)"},
        "is_primary": {"type": "boolean", "description": "Set as primary contact", "default": false}
    },
    "required": ["member_name", "name", "phone", "relationship"]
}

{
    "type": "object",
    "properties": {
        "name": {"type": "string", "description": "Name of the martial art style (e.g., Brazilian Jiu-Jitsu, Karate)"},
        "code": {"type": "string", "description": "Short code (e.g., BJJ, KAR)"},
        "description": {"type": "string", "description": "Description of the style"}
    },
    "required": ["name"]
}
